 import { Component, OnInit, inject, ChangeDetectorRef } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';

@Component({
  selector: 'app-job-search',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './job-search.component.html',
  styleUrls: ['./job-search.component.css']
})
export class JobSearchComponent implements OnInit {
  private cdr = inject(ChangeDetectorRef);

  allJobs: any[] = [];
  searchText: string = '';
  isLoading: boolean = true;

  ngOnInit() {
    this.fetchAvailableJobs();
  }

  // 📥 RÉCUPÉRATION DES ANNONCES DISPONIBLES EN BD
      fetchAvailableJobs() {
    // 🚀 ALIGNEMENT SUR LA NOUVELLE ROUTE ENREGISTRÉE DANS CANDIDATE.ROUTES.JS
    const targetUrl = 'http://localhost:3000/api/candidate/jobs/list'; 
    const token = localStorage.getItem('token'); // Récupération du jeton du candidat connecté

    fetch(targetUrl, {
      method: 'GET',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': token ? `Bearer ${token}` : '' // Passe le middleware de sécurité (VerifyToken)
      }
    })
    .then(async res => {
      if (!res.ok) throw new Error("Erreur de chargement des offres (Code: " + res.status + ")");
      return res.json();
    })
    .then(data => {
      // S'adapte selon si votre backend renvoie directement le tableau ou un objet { jobs: [...] }
      const list = Array.isArray(data) ? data : (data.jobs || []);
      
      // Sécurité : Le candidat ne doit voir que les offres au statut 'disponible' en minuscules
      this.allJobs = list.filter((job: any) => job.status === 'disponible');
      this.isLoading = false;
      this.cdr.detectChanges(); // Force le rendu immédiat des cartes à l'écran
    })
    .catch(err => {
      console.error("Erreur Moteur de recherche MySQL :", err);
      this.isLoading = false;
      this.cdr.detectChanges();
    });
  }



  // 🔍 LOGIQUE DE FILTRAGE PAR SÉLECTION
  get filteredJobs() {
    if (!this.searchText.trim()) return this.allJobs;
    
    return this.allJobs.filter(job => 
      job.title.toLowerCase().includes(this.searchText.toLowerCase()) ||
      job.location.toLowerCase().includes(this.searchText.toLowerCase()) ||
      (job.company_name && job.company_name.toLowerCase().includes(this.searchText.toLowerCase()))
    );
  }

  onOpenApplyModal(job: any) {
    console.log("Ouverture de la modale de postulation pour :", job.title);
    // Cette fonction se connectera plus tard à votre composant 'job-apply-modal'
  }
}

<div class="job-search-container">
  
  <!-- 🔍 ZONE SUPÉRIEURE : BARRE DE RECHERCHE -->
  <div class="search-header-card">
    <div class="search-box-wrapper">
      <i class="bi bi-search search-icon-main"></i>
      <input 
        type="text" 
        [(ngModel)]="searchText" 
        placeholder="Rechercher un métier, des compétences ou une ville (ex: Tunis, Angular...)" 
        class="search-input-main"
      >
    </div>
  </div>

  <!-- ⏳ ÉTATS DE CHARGEMENT -->
  @if (isLoading) {
    <div class="loading-state-box">
      <i class="bi bi-arrow-clockwise spin-animation"></i>
      <p>Recherche des meilleures opportunités en Tunisie...</p>
    </div>
  }

  @if (!isLoading && filteredJobs.length === 0) {
    <div class="empty-state-box">
      <i class="bi bi-briefcase-x"></i>
      <p>Aucune offre d'emploi ne correspond à vos critères actuellement.</p>
    </div>
  }

  <!-- 🚀 GRILLE DES CARTES D'OFFRES D'EMPLOI DYNAMIQUES (3 PAR LIGNE) -->
  @if (!isLoading && filteredJobs.length > 0) {
    <div class="jobs-cards-grid-3">
      @for (job of filteredJobs; track job.id) {
        <div class="job-feed-card">
          <div class="card-top-info">
            <div class="company-logo-placeholder">
              @if (job.company_logo) {
                <img [src]="'http://localhost:3000/logos/' + job.company_logo" alt="Logo">
              } @else {
                <i class="bi bi-building"></i>
              }
            </div>
            <div class="job-title-block">
              <h4 class="feed-job-title">{{ job.title }}</h4>
              <span class="feed-company-name">{{ job.company_name || 'Entreprise Partenaire' }}</span>
            </div>
            <span class="contract-badge-feed">{{ job.contract_type }}</span>
          </div>

          <div class="card-mid-meta">
            <span class="meta-item"><i class="bi bi-geo-alt-fill"></i> {{ job.location }}</span>
            <span class="meta-item"><i class="bi bi-laptop-fill"></i> {{ job.workplace_type }}</span>
            <span class="meta-item"><i class="bi bi-mortarboard-fill"></i> {{ job.experience_level }}</span>
            @if (job.salary) {
              <span class="meta-item salary-tag"><i class="bi bi-cash-stack"></i> {{ job.salary }}</span>
            }
          </div>

          <p class="job-short-desc">
            {{ job.missions_desc | slice:0:100 }}...
          </p>

          <!-- 🔘 PIED DE CARTE AVEC DOUBLE ACTION -->
          <div class="card-bottom-actions">
            <button class="btn-consult-job" (click)="onViewJobDetails(job)">
              <i class="bi bi-eye-fill"></i> Consulter
            </button>

            <!-- Condition de bascule : Déjà postulé vs Postuler -->
            @if (job.isAlreadyApplied) {
              <span class="badge-already-applied">
                <i class="bi bi-check-circle-fill"></i> Déjà postulé
              </span>
            } @else {
              <button class="btn-apply-now" (click)="onOpenApplyModal(job)">
                Postuler <i class="bi bi-arrow-right-short"></i>
              </button>
            }
          </div>
        </div>
      }
    </div>
  }

  <!-- 👁️ CARTE MODALE : DIALOGUE DE CONSULTATION AVANT POSTULATION -->
  @if (selectedJob) {
    <div class="modal-overlay">
      <div class="modal-card">
        <div class="modal-header">
          <h3><i class="bi bi-file-earmark-text-fill"></i> Détails du poste</h3>
          <button (click)="onCloseModal()" class="btn-close-modal"><i class="bi bi-x-lg"></i></button>
        </div>
        <div class="modal-body">
          <div class="detail-row"><strong>Intitulé :</strong> <span>{{ selectedJob.title }}</span></div>
          <div class="detail-row"><strong>Entreprise :</strong> <span>{{ selectedJob.company_name || 'Entreprise' }}</span></div>
          <div class="detail-row"><strong>Contrat & Lieu :</strong> <span>{{ selectedJob.contract_type }} ({{ selectedJob.workplace_type }})</span></div>
          <div class="detail-row"><strong>Localisation :</strong> <span>{{ selectedJob.location }}</span></div>
          <div class="detail-row"><strong>Niveau requis :</strong> <span>{{ selectedJob.experience_level }}</span></div>
          @if (selectedJob.salary) {
            <div class="detail-row"><strong>Salaire indicatif :</strong> <span style="color: #10b981;">{{ selectedJob.salary }}</span></div>
          }
          <div class="detail-block">
            <strong>Missions quotidiennes :</strong>
            <p>{{ selectedJob.missions_desc }}</p>
          </div>
          <div class="detail-block">
            <strong>Profil recherché :</strong>
            <p>{{ selectedJob.profile_desc }}</p>
          </div>
          
          <!-- Action finale à l'intérieur de la modale -->
          <div class="modal-footer-action">
            @if (selectedJob.isAlreadyApplied) {
              <span class="badge-already-applied-large"><i class="bi bi-check-circle-fill"></i> Vous avez déjà postulé à cette offre</span>
            } @else {
              <button class="btn-apply-now-large" (click)="onOpenApplyModal(selectedJob)">
                <i class="bi bi-rocket-takeoff-fill"></i> Envoyer ma candidature maintenant
              </button>
            }
          </div>
        </div>
      </div>
    </div>
  }

</div>
